import React, { useEffect } from 'react';
import { motion } from 'framer-motion';
import gsap from 'gsap';

const Hero = () => {
  const stats = [
    { number: '13+', label: 'Years Experience' },
    { number: '2M+', label: 'Users Impacted' },
    { number: '20+', label: 'Clients Served' },
  ];

  // GSAP entrance timeline — fires once on page load
  useEffect(() => {
    const tl = gsap.timeline({ defaults: { ease: 'power3.out' } });

    gsap.set([
      '.hero-badge',
      '.hero-subtitle',
      '.hero-title-word',
      '.hero-description',
      '.hero-cta',
      '.hero-stats',
      '.hero-image-wrapper',
    ], { opacity: 0 });

    tl.to('.hero-badge',           { opacity: 1, duration: 0.5 })
      .from('.hero-subtitle',      { opacity: 0, y: 24, duration: 0.55 }, '-=0.2')
      .from('.hero-title-word',    { opacity: 0, y: 50, stagger: 0.09, duration: 0.65 }, '-=0.25')
      .from('.hero-description',   { opacity: 0, y: 20, duration: 0.55 }, '-=0.3')
      .from('.hero-cta',           { opacity: 0, y: 20, duration: 0.5 }, '-=0.25')
      .from('.hero-stats',         { opacity: 0, y: 20, duration: 0.5 }, '-=0.2')
      .from('.hero-image-wrapper', { opacity: 0, x: 50, duration: 0.8 }, '-=0.7');

    return () => { tl.kill(); };
  }, []);

  return (
    <section className="hero" id="hero">
      <div className="container">
        <div className="hero-content">
          <div className="hero-text">

            {/* Availability badge */}
            <div className="hero-badge availability-badge">
              <span className="status-dot"></span>
              <span>Available for Work</span>
              <span className="divider">•</span>
              <span>📍 Detroit, MI</span>
            </div>

            {/* Subtitle */}
            <p className="hero-subtitle">
              Omni Designer &amp; Educator
            </p>

            {/* Title — each word wrapped for GSAP stagger */}
            <h1 className="hero-title">
              <span className="hero-title-word">Hi,&nbsp;</span>
              <span className="hero-title-word">I'm&nbsp;</span>
              <span className="hero-title-word name">Scott&nbsp;</span>
              <span className="hero-title-word name">Everett</span>
            </h1>

            {/* Description */}
            <p className="hero-description">
              Leading mission-driven digital experiences for nonprofits, government agencies,
              and social enterprises. Translating complex user needs into intuitive solutions
              that create measurable social impact.
            </p>

            {/* CTA Buttons */}
            <div className="hero-cta">
              <motion.a
                href="#contact"
                className="btn btn-primary"
                whileHover={{ scale: 1.04 }}
                whileTap={{ scale: 0.97 }}
              >
                Get in Touch
              </motion.a>
              <motion.a
                href="#projects"
                className="btn btn-outline"
                whileHover={{ scale: 1.04 }}
                whileTap={{ scale: 0.97 }}
              >
                View My Work
              </motion.a>
            </div>

            {/* Stats */}
            <div className="hero-stats">
              {stats.map((stat, index) => (
                <div className="stat" key={index}>
                  <div className="stat-number">{stat.number}</div>
                  <div className="stat-label">{stat.label}</div>
                </div>
              ))}
            </div>
          </div>

          {/* Hero Image */}
          <div className="hero-image">
            <div className="hero-image-wrapper">
              <div className="hero-image-bg"></div>
              <img
                src="/scott.png"
                alt="Scott Everett"
                className="hero-img"
              />
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
